const data = $input.first().json.body;

const rainRate = parseFloat(data.rainRate) || 0;
const rainHour = parseFloat(data.rainHour) || 0;
const temperature = parseFloat(data.temperature) || 0;
const humidity = parseFloat(data.humidity) || 0;
const phoneNumber = data.phoneNumber || '';

let isCritical = false;
let reason = '';

if (rainRate > 30) { isCritical = true; reason = 'Mưa cực lớn ' + rainRate + ' mi li mét trên giờ. Nguy cơ ngập lụt nghiêm trọng!'; }
else if (rainRate > 22) { isCritical = true; reason = 'Mưa rất lớn ' + rainRate + ' mi li mét trên giờ. Khả năng ngập cao!'; }

if (temperature > 42) { isCritical = true; reason = 'Nhiệt độ cực kỳ nguy hiểm ' + temperature + ' độ C. Nguy cơ cháy rừng!'; }
else if (temperature > 40) { isCritical = true; reason = 'Nắng nóng cực độ ' + temperature + ' độ C. Nguy cơ sốc nhiệt!'; }

if (humidity > 0 && humidity < 20 && temperature > 35) {
  isCritical = true;
  reason = 'Độ ẩm cực thấp ' + humidity + ' phần trăm kết hợp nhiệt độ ' + temperature + ' độ. Nguy cơ hỏa hoạn!';
}

const voiceMessage = 'Cảnh báo khẩn cấp từ Trạm IoT! ' + reason + ' Vui lòng kiểm tra ngay và di chuyển đến nơi an toàn! Lặp lại, ' + reason;

const twiml = '<Response><Pause length="1"/><Say language="vi-VN" voice="Google.vi-VN-Standard-A">' + voiceMessage + '</Say><Pause length="2"/><Say language="vi-VN" voice="Google.vi-VN-Standard-A">' + voiceMessage + '</Say></Response>';

return [{ json: { isCritical, reason, voiceMessage, twiml, phoneNumber, rainRate, rainHour, temperature, humidity } }];
